select v_1 as "n_nationkey", v_2 as "n_name", v_3 as "n_regionkey", v_4 as "n_comment" from (select v_5 as v_1, v_6 as v_2, v_7 as v_3, v_8 as v_4, v_9 as v_10 from (select * from (select * from (select *, row_number() over () as v_9 from (select "n_nationkey" as v_5, "n_name" as v_6, "n_regionkey" as v_7, "n_comment" as v_8 from "nation") s) s) l inner join (select * from (select "r_regionkey" as v_11, "r_name" as v_12, "r_comment" as v_13 from "region") s where v_12 = 'ASIA') r on v_7 = v_11) s group by 1, 2, 3, 4, 5) s
